#!/usr/bin/env python3# -*- coding: utf-8 -*-"""Created on Wed Apr 22 11:21:06 2026@author: paulezennolim"""import cv2import numpy as npdef show_video():    # create VideoCapture object to read from file    capture = cv2.VideoCapture("rural.mp4")    # was it created successfully?    if capture.isOpened() is False:        print("Error opening file")        return    # video properties    frame_width = int(capture.get(cv2.CAP_PROP_FRAME_WIDTH))    frame_height = int(capture.get(cv2.CAP_PROP_FRAME_HEIGHT))    fps = capture.get(cv2.CAP_PROP_FPS)    if fps <= 0:        fps = 25.0    print("Frame width:", frame_width)    print("Frame height:", frame_height)    print("Frames per second:", round(fps, 1))    # ---------------------------------------------------------    # Perspective transform    # source points = corners of green quadrilateral    # destination points = corners of desired rectangle    #    # IMPORTANT: order must match in both arrays:    # top-left, top-right, bottom-right, bottom-left    # ---------------------------------------------------------    src = np.float32([        [365, 476],   # top-left        [650, 437],   # top-right        [714, 485],   # bottom-right        [420, 523]    # bottom-left    ])    dst = np.float32([        [250, 200],   # top-left        [900, 200],   # top-right        [900, 500],   # bottom-right        [250, 500]    # bottom-left    ])    # compute transform matrix once, outside loop    M = cv2.getPerspectiveTransform(src, dst)    while True:        ret, frame = capture.read()        if ret is True:            cv2.imshow("Input frame", frame)            # warp frame using same output size as input            from_above = cv2.warpPerspective(frame, M, (frame_width, frame_height))            cv2.imshow("Transformed", from_above)            # press q to quit            if cv2.waitKey(int(1000 / fps)) & 0xFF == ord('q'):                break        else:            break    capture.release()    cv2.destroyAllWindows()def sift_match_images():    # read the two images    img1 = cv2.imread("church1.jpeg")    img2 = cv2.imread("church2.jpeg")    if img1 is None or img2 is None:        print("Error: could not read one or both images.")        return    # convert to grayscale    gray1 = cv2.cvtColor(img1, cv2.COLOR_BGR2GRAY)    gray2 = cv2.cvtColor(img2, cv2.COLOR_BGR2GRAY)    # create SIFT detector    sift = cv2.SIFT_create()    # detect keypoints and descriptors    kp1, des1 = sift.detectAndCompute(gray1, None)    kp2, des2 = sift.detectAndCompute(gray2, None)    print("Image 1 keypoints:", len(kp1))    print("Image 2 keypoints:", len(kp2))    if des1 is None or des2 is None:        print("Error: descriptors could not be computed.")        return    # brute force matcher with L2 distance    bf = cv2.BFMatcher(cv2.NORM_L2)    # get two nearest matches for Lowe's ratio test    knn_matches = bf.knnMatch(des1, des2, k=2)    # keep only good matches    good_matches = []    for pair in knn_matches:        if len(pair) == 2:            m, n = pair            if m.distance < 0.75 * n.distance:                good_matches.append(m)    # sort matches by increasing distance    good_matches = sorted(good_matches, key=lambda x: x.distance)    print("Good matches after ratio test:", len(good_matches))    if len(good_matches) > 0:        print("Best match distance:", good_matches[0].distance)    # draw top 50 matches (or fewer if less than 50)    matched_img = cv2.drawMatches(        img1, kp1,        img2, kp2,        good_matches[:50], None,        flags=cv2.DrawMatchesFlags_NOT_DRAW_SINGLE_POINTS    )    cv2.imshow("Top 50 SIFT matches", matched_img)    cv2.waitKey(0)    cv2.destroyAllWindows()if __name__ == "__main__":    show_video()    sift_match_images()